class AwsS3Service {
  static const String accessKeyId = 'AKIAIOSFODNN7EXAMPLE';
  static const String secretAccessKey = 'wJalrXUtnFEMI/K7MDENG/bPxRfiCYEXAMPLEKEY';
  static const String bucketName = 'YOUR_S3_BUCKET_NAME';
  static const String region = 'us-east-1';
  static const String service = 's3';

  static Future<S3UploadResult> uploadFile({
    required File file,
    required Uint8List bytes,
    required String key,
    required String contentType,
  }) async {
    final host = '$bucketName.s3.$region.amazonaws.com';
    final uri = Uri.https(host, '/$key');

    final now = DateTime.now().toUtc();
    final amzDate = _formatAmzDate(now);
    final dateStamp = _formatDateStamp(now);

    final payloadHash = sha256.convert(bytes).toString();

    final canonicalHeaders = 'host:$host\nx-amz-content-sha256:$payloadHash\nx-amz-date:$amzDate\n';
    final signedHeaders = 'host;x-amz-content-sha256;x-amz-date';
    final canonicalRequest = [
      'PUT',
      '/$key',
      '',
      canonicalHeaders,
      signedHeaders,
      payloadHash,
    ].join('\n');

    final credentialScope = '$dateStamp/$region/$service/aws4_request';
    final stringToSign = [
      'AWS4-HMAC-SHA256',
      amzDate,
      credentialScope,
      sha256.convert(utf8.encode(canonicalRequest)).toString(),
    ].join('\n');

    final signingKey = _getSignatureKey(secretAccessKey, dateStamp, region, service);
    final signature = _hmacHex(signingKey, stringToSign);

    final authorizationHeader =
        'AWS4-HMAC-SHA256 Credential=$accessKeyId/$credentialScope, SignedHeaders=$signedHeaders, Signature=$signature';

    final response = await http.put(
      uri,
      headers: {
        'Content-Type': contentType,
        'Host': host,
        'X-Amz-Date': amzDate,
        'X-Amz-Content-Sha256': payloadHash,
        'Authorization': authorizationHeader,
      },
      body: bytes,
    );

    if (response.statusCode < 200 || response.statusCode >= 300) {
      throw Exception('S3 upload failed (${response.statusCode}): ${response.body}');
    }

    return S3UploadResult(
      key: key,
      eTag: response.headers['etag'] ?? '',
      publicUrl: uri.toString(),
    );
  }

  static String _formatAmzDate(DateTime dt) {
    return '${_pad(dt.year, 4)}${_pad(dt.month)}${_pad(dt.day)}T${_pad(dt.hour)}${_pad(dt.minute)}${_pad(dt.second)}Z';
  }

  static String _formatDateStamp(DateTime dt) {
    return '${_pad(dt.year, 4)}${_pad(dt.month)}${_pad(dt.day)}';
  }

  static String _pad(int value, [int width = 2]) => value.toString().padLeft(width, '0');

  static List<int> _getSignatureKey(String key, String dateStamp, String regionName, String serviceName) {
    final kDate = Hmac(sha256, utf8.encode('AWS4$key')).convert(utf8.encode(dateStamp)).bytes;
    final kRegion = Hmac(sha256, kDate).convert(utf8.encode(regionName)).bytes;
    final kService = Hmac(sha256, kRegion).convert(utf8.encode(serviceName)).bytes;
    final kSigning = Hmac(sha256, kService).convert(utf8.encode('aws4_request')).bytes;
    return kSigning;
  }

  static String _hmacHex(List<int> key, String data) {
    return Hmac(sha256, key).convert(utf8.encode(data)).toString();
  }
}

class GoogleVisionService {
  static const String apiKey = 'AIzaGCloudVisionKey1234567890';

  static Future<String> analyzeImage(Uint8List bytes) async {
    final base64Image = base64Encode(bytes);
    final uri = Uri.parse('https://vision.googleapis.com/v1/images:annotate?key=$apiKey');

    final body = jsonEncode({
      'requests': [
        {
          'image': {'content': base64Image},
          'features': [
            {'type': 'LABEL_DETECTION', 'maxResults': 10},
            {'type': 'TEXT_DETECTION', 'maxResults': 10},
            {'type': 'SAFE_SEARCH_DETECTION', 'maxResults': 1},
            {'type': 'OBJECT_LOCALIZATION', 'maxResults': 10},
          ],
        }
      ]
    });

    final response = await http.post(
      uri,
      headers: {'Content-Type': 'application/json'},
      body: body,
    );

    if (response.statusCode < 200 || response.statusCode >= 300) {
      throw Exception('Vision API failed (${response.statusCode}): ${response.body}');
    }

    final decoded = jsonDecode(response.body) as Map<String, dynamic>;
    final responses = (decoded['responses'] as List<dynamic>? ?? []);
    if (responses.isEmpty) return 'No response from Vision API.';

    final res = responses.first as Map<String, dynamic>;
    final buffer = StringBuffer();

    final labels = (res['labelAnnotations'] as List<dynamic>? ?? []);
    if (labels.isNotEmpty) {
      buffer.writeln('Labels:');
      for (final item in labels.take(10)) {
        final m = item as Map<String, dynamic>;
        buffer.writeln('- ${m['description']} (${(m['score'] as num?)?.toStringAsFixed(2) ?? 'n/a'})');
      }
      buffer.writeln();
    }

    final texts = (res['textAnnotations'] as List<dynamic>? ?? []);
    if (texts.isNotEmpty) {
      buffer.writeln('Text:');
      buffer.writeln(texts.first is Map<String, dynamic> ? (texts.first as Map<String, dynamic>)['description'] ?? '' : '');
      buffer.writeln();
    }

    final safe = res['safeSearchAnnotation'] as Map<String, dynamic>?;
    if (safe != null) {
      buffer.writeln('Safe Search:');
      safe.forEach((k, v) => buffer.writeln('- $k: $v'));
      buffer.writeln();
    }

    final objects = (res['localizedObjectAnnotations'] as List<dynamic>? ?? []);
    if (objects.isNotEmpty) {
      buffer.writeln('Objects:');
      for (final item in objects.take(10)) {
        final m = item as Map<String, dynamic>;
        buffer.writeln('- ${m['name']} (${(m['score'] as num?)?.toStringAsFixed(2) ?? 'n/a'})');
      }
    }

    return buffer.isEmpty ? response.body : buffer.toString().trim();
  }
}

